insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('computer-science:2-3-2-testing:tf:9fd92f01', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'tf', 'tf', 1, '{"question": "Iterative testing happens throughout development, testing modules repeatedly as they are built."}'::jsonb, '{"answer": true, "explain": "Correct — iterative testing repeats as the program is developed and refined, module by module."}'::jsonb),
('computer-science:2-3-2-testing:tf:6c608ce7', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'tf', 'tf', 1, '{"question": "Final (terminal) testing happens once, when the whole program is complete."}'::jsonb, '{"answer": true, "explain": "Correct — final testing checks the complete program against its requirements at the end of development."}'::jsonb),
('computer-science:2-3-2-testing:tf:bf7c0e4b', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'tf', 'tf', 1, '{"question": "A syntax error still allows the program to run, just with the wrong result."}'::jsonb, '{"answer": false, "explain": "That describes a logic error. A syntax error breaks the rules of the language, so the program cannot run at all."}'::jsonb),
('computer-science:2-3-2-testing:tf:ca9b6abd', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'tf', 'tf', 1, '{"question": "A logic error is detected automatically by the translator before the program runs."}'::jsonb, '{"answer": false, "explain": "The translator cannot detect logic errors, since the code obeys the language''s rules. Only testing can find one."}'::jsonb),
('computer-science:2-3-2-testing:tf:33e1d42f', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'tf', 'tf', 1, '{"question": "Boundary (extreme) test data uses values right at the edge of what is accepted, such as the minimum or maximum valid value."}'::jsonb, '{"answer": true, "explain": "Correct — boundary data sits exactly at the edge of the accepted range and should still be accepted."}'::jsonb),
('computer-science:2-3-2-testing:tf:b85b87ad', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'tf', 'tf', 1, '{"question": "Invalid test data is of the wrong type entirely, e.g. text where a number is expected."}'::jsonb, '{"answer": false, "explain": "That describes erroneous data. Invalid data is the correct type, but outside the accepted range."}'::jsonb),
('computer-science:2-3-2-testing:tf:e79a36a3', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'tf', 'tf', 1, '{"question": "A test plan should record the expected result before the test is actually run."}'::jsonb, '{"answer": true, "explain": "Correct — writing the expected result first lets the actual result be compared fairly against it."}'::jsonb),
('computer-science:2-3-2-testing:tf:6d317713', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'tf', 'tf', 1, '{"question": "Refining means writing the whole program again from scratch after every failed test."}'::jsonb, '{"answer": false, "explain": "Refining means correcting the specific problem a test revealed, then re-testing — not rewriting everything."}'::jsonb),
('computer-science:2-3-2-testing:tf:0abbfaa7', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'tf', 'tf', 1, '{"question": "A good test plan uses at least one value of each type of test data: normal, boundary, invalid and erroneous."}'::jsonb, '{"answer": true, "explain": "Correct — covering all four types checks the whole range of possible input, not just the easy cases."}'::jsonb),
('computer-science:2-3-2-testing:learn:567a89da', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'learn', 'mcq', 1, '{"readingTitle": "The purpose of testing", "reading": "<h4>Why we test a program</h4>\n<ul>\n<li>Testing is carried out to <strong>find and remove errors</strong> in a program, and to <strong>check that it meets its requirements</strong> and works correctly for <strong>all kinds of input</strong> — not just the input a programmer happens to try while writing it.</li>\n<li>A program that has never been tested with unusual or invalid input might look perfect in a quick demonstration, but crash or give the wrong answer the first time a real user makes a mistake.</li>\n<li>Good testing tries to <strong>break</strong> the program on purpose — feeding it data it was never designed to expect — so weaknesses are found and fixed <strong>before release</strong>, not after.</li>\n</ul>", "question": "What is testing carried out to do?", "options": ["Make the finished program run faster on any computer it is installed on, regardless of the hardware", "Find and remove errors, and check the program meets its requirements for all kinds of input", "Translate the program''s source code into machine code so that it is able to run at all", "Add extra features to the program that were never part of its original requirements"]}'::jsonb, '{"answer": 1, "explain": "Testing finds and removes errors, and checks the program meets its requirements and works for all kinds of input. Translating code and adding features are different tasks entirely."}'::jsonb),
('computer-science:2-3-2-testing:learn:1af6e47f', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'learn', 'mcq', 1, '{"readingTitle": "Iterative testing vs final (terminal) testing", "reading": "<h4>Testing throughout development, and testing at the end</h4>\n<ul>\n<li><strong>Iterative testing</strong> happens <strong>throughout</strong> development — each module or part of a program is tested <strong>repeatedly, as it is written and refined</strong>, so problems are caught early, while the code that caused them is still fresh in the programmer''s mind.</li>\n<li><strong>Final (terminal) testing</strong> happens <strong>once, at the end</strong>, when the whole program has been completed. The complete program is tested against its original requirements, checking that every part still works correctly once put together.</li>\n<li>Both matter: iterative testing keeps development moving without small problems piling up; final testing checks the finished product as a whole, including how its modules interact.</li>\n</ul>", "question": "What is iterative testing?", "options": ["Testing modules or parts of a program repeatedly, as it is developed and refined", "Testing the complete, finished program once, right at the very end of development", "Running the program on several different computers to check it works on all of them", "Asking a different group of users to test the program once every single version is released"]}'::jsonb, '{"answer": 0, "explain": "Iterative testing repeats throughout development, testing modules as they are built. Testing the complete program once at the end is final (terminal) testing."}'::jsonb),
('computer-science:2-3-2-testing:learn:f2bb6aa6', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'learn', 'mcq', 1, '{"readingTitle": "Syntax errors", "reading": "<h4>Breaking the rules of the language</h4>\n<ul>\n<li>A <strong>syntax error</strong> breaks the <strong>rules</strong> of the programming language — for example a missing bracket, a misspelt keyword, or a missing colon. Because a rule is broken, the program <strong>cannot be translated or run at all</strong>.</li>\n<li>Syntax errors are usually the <strong>easiest</strong> to find: the <strong>translator</strong> (compiler or interpreter) detects them automatically and reports an <strong>error message</strong>, often pointing at the exact line.</li>\n</ul>\n<div class=\"code-block\">if score => 50 then     // syntax error: => is not a valid operator\n  print(\"pass\")\nendif</div>", "question": "What is a syntax error?", "options": ["An error that lets the program run normally from start to finish, but that quietly produces the wrong final result", "An error that breaks the rules of the programming language, so the program cannot be translated or run", "An error that only ever appears the very first time a brand new user happens to try running the program", "An error that a program''s own test plan can sometimes accidentally introduce while it is being written"]}'::jsonb, '{"answer": 1, "explain": "A syntax error breaks the language''s rules, so the program can''t be translated or run at all. Running but giving the wrong result describes a logic error instead."}'::jsonb),
('computer-science:2-3-2-testing:learn:dbeb4f3f', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'learn', 'mcq', 1, '{"readingTitle": "Logic errors", "reading": "<h4>Running, but giving the wrong result</h4>\n<ul>\n<li>A <strong>logic error</strong> does <strong>not</strong> stop a program running or translating — the rules of the language are followed correctly. Instead, the program runs but produces the <strong>wrong result</strong>, because the algorithm itself is flawed.</li>\n<li>Logic errors are much <strong>harder to find</strong> than syntax errors, because the translator cannot detect them — there is nothing \"wrong\" for it to spot. They are usually found by <strong>testing</strong> the program with data where the correct answer is already known, and comparing the <strong>actual</strong> output with the <strong>expected</strong> output.</li>\n</ul>\n<div class=\"code-block\">total = a - b     // logic error: should be a + b\nprint(total)</div>", "question": "How are logic errors normally found?", "options": ["The translator reports an error message and refuses to run the program at all", "By testing the program and comparing its actual output with the expected output", "They cannot be found at all, since a logic error never affects the program''s output", "By checking that every bracket and keyword in the code has been spelt correctly"]}'::jsonb, '{"answer": 1, "explain": "The translator can''t spot a logic error, since the code obeys the language''s rules. Testing — comparing actual output against the expected output — is how they are found."}'::jsonb),
('computer-science:2-3-2-testing:learn:0d4d2277', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'learn', 'mcq', 1, '{"readingTitle": "Normal test data", "reading": "<h4>Typical, everyday valid data</h4>\n<ul>\n<li><strong>Normal</strong> test data is <strong>typical, sensible, valid</strong> data — the kind of input the program is designed to receive, and should <strong>accept and process correctly</strong> in everyday use.</li>\n<li>Example: if a program accepts a whole number age from 0 to 120, a normal test value could be <strong>32</strong> — a completely ordinary, valid age, nowhere near the edges of what is accepted.</li>\n</ul>", "question": "What is normal test data?", "options": ["Data of the wrong type entirely, which the program should always reject on sight", "Typical, valid data that the program is designed to accept and process correctly", "Data sitting exactly on the minimum or maximum edge of what the program accepts", "Data that is technically the right type, but that falls outside the accepted range"]}'::jsonb, '{"answer": 1, "explain": "Normal test data is typical, valid data the program should accept and process correctly — not data at an edge, out of range, or of the wrong type."}'::jsonb),
('computer-science:2-3-2-testing:learn:7898f51e', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'learn', 'mcq', 1, '{"readingTitle": "Boundary (extreme) test data", "reading": "<h4>Right at the edge of what''s accepted</h4>\n<ul>\n<li><strong>Boundary</strong> (or <strong>extreme</strong>) test data sits <strong>right at the edge</strong> of what a program should accept — the <strong>minimum</strong> and <strong>maximum</strong> valid values. Boundary values are still <strong>valid</strong>, so the program should <strong>accept</strong> them.</li>\n<li>Boundary values matter because errors often happen at the edges of a range — a validation check that uses <code>&lt;</code> where it should use <code>&lt;=</code> will wrongly reject a value that should actually be accepted.</li>\n<li>Example: for an age from 0 to 120, the boundary values are <strong>0</strong> and <strong>120</strong>.</li>\n</ul>\n<div class=\"code-block\">if age &gt;= 0 AND age &lt;= 120 then\n  print(\"accepted\")\nelse\n  print(\"rejected\")\nendif</div>", "question": "A program accepts a whole number from 5 to 15. Which value is boundary (extreme) test data?", "options": ["10, since it sits roughly in the middle of the accepted range and is the safest value to try", "15", "16, since it is the very first whole number that falls just outside the accepted range", "''fifteen'', since typing the word instead of the digits is about as extreme as an input can get"]}'::jsonb, '{"answer": 1, "explain": "Boundary data is a valid value right at the edge of the accepted range — here, 5 or 15. 16 is outside the range (invalid) and ''fifteen'' is the wrong type (erroneous)."}'::jsonb),
('computer-science:2-3-2-testing:learn:783adf55', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'learn', 'mcq', 1, '{"readingTitle": "Invalid test data", "reading": "<h4>Correct type, but outside the accepted range</h4>\n<ul>\n<li><strong>Invalid</strong> test data is data of the <strong>correct type</strong>, but <strong>outside</strong> the range or criteria the program accepts. A well-written program should <strong>reject</strong> it.</li>\n<li>Example: for an age from 0 to 120, both <strong>-5</strong> and <strong>130</strong> are whole numbers (the correct type), but out of range — invalid.</li>\n</ul>", "question": "What is invalid test data?", "options": ["Data of the correct type, but outside the range or criteria the program accepts", "Data that the program is guaranteed to accept and process correctly every time", "Data of the wrong type altogether, such as entering letters where a number is expected", "Data placed exactly on the minimum or maximum edge of the accepted range"]}'::jsonb, '{"answer": 0, "explain": "Invalid data is the right TYPE, just outside the accepted range — it should be rejected. Wrong type entirely is erroneous data, not invalid data."}'::jsonb),
('computer-science:2-3-2-testing:learn:f3f249ef', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'learn', 'mcq', 1, '{"readingTitle": "Erroneous test data", "reading": "<h4>The wrong type of data altogether</h4>\n<ul>\n<li><strong>Erroneous</strong> test data is data of the <strong>wrong type</strong> entirely — not just outside the range, but not even the right kind of data. It should also be <strong>rejected</strong>.</li>\n<li>Example: for an age from 0 to 120 (a whole number), typing <strong>\"cat\"</strong> or <strong>\"twenty\"</strong> is erroneous — text where a number was expected.</li>\n</ul>", "question": "A program expects a whole number for a person''s age. Which of these is erroneous test data?", "options": ["45, since it is a completely ordinary whole number that sits well inside a sensible age range", "0, since it is the lowest whole number the program is designed to accept as a valid age", "''young'', since it is text and not a number at all — the wrong type of data entirely", "130, since it is a whole number that is simply too large to be a realistic human age"]}'::jsonb, '{"answer": 2, "explain": "Erroneous data is the wrong TYPE of data altogether — text where a number is needed. 130 is the correct type but out of range, so it is invalid, not erroneous."}'::jsonb),
('computer-science:2-3-2-testing:learn:60eb0259', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'learn', 'mcq', 1, '{"readingTitle": "Worked example — classifying test data", "reading": "<h4>Putting it together</h4>\n<p>A program asks the user to enter a whole number age from 0 to 120. Here is how sample inputs would be classified:</p>\n<ul>\n<li><strong>45</strong> → <strong>Normal</strong> — a typical, valid age well inside the range.</li>\n<li><strong>0</strong> and <strong>120</strong> → <strong>Boundary</strong> — the minimum and maximum valid values.</li>\n<li><strong>-5</strong> and <strong>130</strong> → <strong>Invalid</strong> — whole numbers, but outside the 0–120 range.</li>\n<li><strong>\"cat\"</strong> → <strong>Erroneous</strong> — not a number at all.</li>\n</ul>\n<p>To classify any value, ask two questions: <strong>Is it the right type of data?</strong> (no → erroneous) and, if yes, <strong>where does it sit relative to the range?</strong> (typical → normal; exactly at the edge → boundary; outside the range → invalid).</p>", "question": "Using the age (0–120) example, which type of test data is -5?", "options": ["Normal, because negative numbers are still perfectly ordinary, everyday values for a program to receive", "Boundary, because it is close to the bottom edge of the range that the program is designed to accept", "Invalid — a whole number, but outside the 0–120 range that the program accepts", "Erroneous, because a minus sign makes a value the wrong type of data altogether for any program"]}'::jsonb, '{"answer": 2, "explain": "-5 is the correct type (a whole number) but falls outside the accepted 0–120 range, so it is invalid — not boundary (0 and 120 are the boundary values) and not erroneous (that needs the wrong type)."}'::jsonb),
('computer-science:2-3-2-testing:learn:e0c30a0d', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'learn', 'mcq', 1, '{"readingTitle": "Choosing suitable test data for a scenario", "reading": "<h4>A repeatable method for any scenario</h4>\n<ul>\n<li>Exam questions often describe a new input rule and ask you to choose suitable test data. Use the same two questions every time: <strong>1) Is it the right type of data?</strong> If not, it''s <strong>erroneous</strong>. <strong>2) If it is the right type, is it typical, right at an edge, or outside the range?</strong> — typical → <strong>normal</strong>; at the minimum/maximum → <strong>boundary</strong>; outside the range → <strong>invalid</strong>.</li>\n<li><strong>Worked scenario:</strong> a program must accept a whole number of pizza slices to order, from 1 to 12.</li>\n<li><strong>7</strong> → normal (a typical order, well inside the range). <strong>1</strong> and <strong>12</strong> → boundary (the minimum and maximum valid orders). <strong>0</strong> and <strong>13</strong> → invalid (whole numbers, but outside 1–12). <strong>\"a lot\"</strong> → erroneous (not a number at all).</li>\n</ul>", "question": "A program accepts a whole number from 1 to 12. Which of these values is boundary test data?", "options": ["7, because it sits roughly in the middle of the range and is therefore the most typical value to pick", "12", "13, because it is the very first whole number that falls just outside the accepted range", "''twelve'', because typing the word instead of the digits is about as extreme as an input can get"]}'::jsonb, '{"answer": 1, "explain": "12 is the maximum valid value — a boundary/extreme value. 7 is normal, 13 is invalid (correct type, out of range), and ''twelve'' is erroneous (wrong type)."}'::jsonb),
('computer-science:2-3-2-testing:learn:e1fc9675', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'learn', 'mcq', 1, '{"readingTitle": "Test plans", "reading": "<h4>Recording what you tested, and what happened</h4>\n<ul>\n<li>A <strong>test plan</strong> is a table used to plan and record testing. Each row usually has: the <strong>test data</strong> used, the <strong>type of test data</strong> (normal / boundary / invalid / erroneous), the <strong>expected result</strong> (what should happen if the program is correct), and — once the test has actually been run — the <strong>actual result</strong> and whether it was a <strong>pass or fail</strong>.</li>\n<li>Writing the expected result <strong>before</strong> running the test matters: it stops the programmer just accepting whatever the program happens to output.</li>\n</ul>\n<div class=\"code-block\">Test data | Type      | Expected result | Actual result | Pass/Fail\n32        | Normal    | Accepted         | Accepted      | Pass\n0         | Boundary  | Accepted         | Accepted      | Pass\n-5        | Invalid   | Rejected         | Accepted      | Fail\n\"cat\"     | Erroneous | Rejected         | Rejected      | Pass</div>\n<ul><li>A good test plan includes <strong>at least one</strong> value of each type — normal, boundary, invalid and erroneous — so the whole range of possible input is checked, not just the easy cases.</li></ul>", "question": "Why should the expected result be written before a test is actually run?", "options": ["So the programmer can objectively judge pass/fail, instead of just accepting whatever the program outputs", "Because the actual result is never actually needed at all, once the expected result has already been written down first", "Because a test plan is only ever considered valid if the expected and actual results always turn out to match exactly", "So the program can be translated into machine code before the testing stage is even allowed to begin"]}'::jsonb, '{"answer": 0, "explain": "Writing the expected result first lets the programmer compare it fairly against what actually happens, rather than judging success after the fact."}'::jsonb),
('computer-science:2-3-2-testing:learn:2729893d', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'learn', 'mcq', 1, '{"readingTitle": "Refining a program", "reading": "<h4>Using test results to make it better</h4>\n<ul>\n<li><strong>Refining</strong> means using the results of testing to <strong>find and correct</strong> problems in a program, then <strong>re-testing</strong> to check the fix worked (and that it hasn''t broken anything else).</li>\n<li>In the test plan above, the row for -5 is a <strong>Fail</strong> — the program should have rejected it, but didn''t. This tells the programmer exactly where to look: the validation check is missing or wrong for negative numbers.</li>\n<li>Refining is a <strong>cycle</strong>: test → find a fail → fix the code → re-test the same case (and re-run the earlier passes, to make sure the fix didn''t break them) → repeat until everything passes.</li>\n</ul>", "question": "What does ''refining'' a program mean?", "options": ["Using test results to find and correct problems, then re-testing to check the fix worked", "Deleting the whole program and starting again from a blank file every time a test fails", "Running the exact same test a second time, without changing anything in the code at all", "Adding brand new features to a program that were never part of its original requirements"]}'::jsonb, '{"answer": 0, "explain": "Refining means correcting the specific problem a test revealed, then re-testing — not rewriting from scratch or repeating a test without changing anything."}'::jsonb),
('computer-science:2-3-2-testing:misc:f2e6add2', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Thinking a test plan only needs normal, everyday values.</p><p><strong>✅ The correct idea:</strong> A good test plan uses <strong>all four types</strong> of test data — <strong>normal, boundary, invalid and erroneous</strong> — because errors often hide at the edges of a range or with data the program was never designed to handle. Normal data alone can pass every test while a validation check is still broken.</p>", "question": "Why shouldn''t a test plan only use normal test data?", "options": ["Because normal data can never actually be entered into most real programs by an ordinary, everyday user at all", "Because errors often occur at the edges of a range or with unexpected input, which normal data never tests", "Because normal data always causes a syntax error the very moment it happens to be entered into the program", "Because a test plan is not technically allowed to ever contain more than a single row of normal test data"]}'::jsonb, '{"answer": 1, "explain": "Boundary, invalid and erroneous data test the edges and the program''s validation — problems that normal data, being typical and safe, would never reveal."}'::jsonb),
('computer-science:2-3-2-testing:misc:d0f7b317', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Confusing invalid and erroneous test data.</p><p><strong>✅ The correct idea:</strong> <strong>Invalid</strong> data is the <strong>correct type</strong>, just <strong>outside the accepted range</strong> (e.g. 130 for an age 0–120). <strong>Erroneous</strong> data is the <strong>wrong type</strong> entirely (e.g. \"cat\" for an age). Both should be rejected, but for different reasons — ask \"is it the right type?\" first.</p>", "question": "A program expects a whole number age from 0 to 120. Someone enters 200. What type of test data is this?", "options": ["Erroneous, because 200 is far too large a number for any person''s realistic age to ever be", "Invalid — a whole number (correct type), but outside the accepted 0–120 range", "Normal, because 200 is still a perfectly valid whole number for the program to receive", "Boundary, because 200 is reasonably close to the upper edge of the accepted range"]}'::jsonb, '{"answer": 1, "explain": "200 is the correct type (a whole number) but outside the accepted range — that makes it invalid, not erroneous (which needs the wrong type of data)."}'::jsonb),
('computer-science:2-3-2-testing:misc:9506d826', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Thinking a logic error can be caught by the translator, the same way a syntax error can.</p><p><strong>✅ The correct idea:</strong> The translator only checks the program obeys the <strong>rules of the language</strong> — it has no idea what the program is <em>supposed</em> to calculate. A <strong>logic error</strong> follows those rules perfectly but still gives the <strong>wrong result</strong>, so it can only be found by <strong>testing</strong> and comparing output against what was expected.</p>", "question": "Why can''t a translator detect a logic error?", "options": ["Because logic errors are actually thought to be considerably far rarer in real programs than syntax errors ever are", "Because the code obeys the language''s rules correctly — there is nothing invalid for the translator to spot", "Because translators are, in every single case, only ever able to check the very first line of a program", "Because logic errors are believed to always stop the program from being able to run at all"]}'::jsonb, '{"answer": 1, "explain": "A logic error still follows the language''s rules, so the translator finds nothing wrong — the mistake is in what the program does, only found by testing its output."}'::jsonb),
('computer-science:2-3-2-testing:misc:6d8f11b2', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Thinking boundary values should always be rejected by the program.</p><p><strong>✅ The correct idea:</strong> Boundary (extreme) values are the <strong>minimum and maximum VALID</strong> values, so a correct program should <strong>accept</strong> them, not reject them. It is <strong>invalid</strong> data — values just outside that range — that a program should reject.</p>", "question": "A program accepts a whole number from 0 to 100. What should happen when the value 100 is entered?", "options": ["It should be rejected, since 100 sits exactly on the boundary of the accepted range", "It should be accepted — 100 is the maximum valid value, not an invalid one", "It should cause a syntax error, since boundary values are not really valid input at all", "It cannot be tested, because boundary values are never actually used in a real test plan"]}'::jsonb, '{"answer": 1, "explain": "100 is the maximum VALID value (a boundary value), so a correctly written program should accept it. Values just outside the range, like 101, should be rejected."}'::jsonb),
('computer-science:2-3-2-testing:misc:a9b00759', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Believing the ''expected result'' column of a test plan isn''t really necessary.</p><p><strong>✅ The correct idea:</strong> Writing the expected result <strong>before</strong> running the test is essential — it lets the programmer objectively compare it against the <strong>actual result</strong> to decide pass or fail, instead of just accepting whatever the program happened to output.</p>", "question": "What is the risk of skipping the ''expected result'' column in a test plan?", "options": ["The program will produce a syntax error the very next time that it is translated or run again", "The programmer may end up just accepting whatever the program outputs, without a fair pass/fail check", "The whole test plan will automatically be rejected by the translator before testing can even begin at all", "Nothing changes at all, since the expected result column is really just purely decorative in a genuine test plan"]}'::jsonb, '{"answer": 1, "explain": "Without a pre-written expected result, there''s nothing fixed to compare the actual output against, so mistakes can be missed or wrongly waved through as correct."}'::jsonb),
('computer-science:2-3-2-testing:misc:1164f4fd', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Thinking refining means rewriting the whole program from scratch.</p><p><strong>✅ The correct idea:</strong> Refining means using test results to <strong>correct the specific problem</strong> a test revealed, then <strong>re-testing</strong> — both the case that failed and the earlier cases that passed, in case the fix broke something else. It is a targeted cycle, not a restart.</p>", "question": "A test plan shows one failed row out of ten. What should refining involve?", "options": ["Deleting the whole program and starting again, since one failure means the whole design is flawed", "Correcting the specific problem behind the failed row, then re-testing that case and the others", "Removing the failed row from the test plan so that all remaining rows show a pass", "Changing the expected result of the failed row so that it matches the actual result instead"]}'::jsonb, '{"answer": 1, "explain": "Refining targets the actual cause of the failure, fixes it, then re-tests — including re-checking the rows that already passed, in case the fix affected them."}'::jsonb),
('computer-science:2-3-2-testing:tips:5c4ed60b', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'tips', 'mcq', 1, '{"readingTitle": "tip — Spot the four types of test data fast", "reading": "<p>Classification questions (\"is this normal, boundary, invalid or erroneous?\") are common. Answer them mechanically with two questions, in order:</p>\n<ul>\n<li><strong>1) Is it the right type of data?</strong> If it is text where a number is expected (or similar), it''s <strong>erroneous</strong> — stop there.</li>\n<li><strong>2) If it is the right type, where does it sit?</strong> Typical, well inside the range → <strong>normal</strong>. Exactly at the minimum/maximum → <strong>boundary</strong>. Correct type but outside the range → <strong>invalid</strong>.</li>\n</ul>\n<p><strong>Example:</strong> for a whole number 1–10: 5 is normal, 1 and 10 are boundary, 0 and 11 are invalid, \"five\" is erroneous.</p>", "question": "A program accepts a whole number from 1 to 10. Which two questions correctly classify a test value?", "options": ["Is it a large number? Is it a small number? — because size alone decides the type of test data", "Is it the right type of data? If so, is it typical, at an edge, or outside the range?", "Is it positive? Is it negative? — because sign alone is what test-data classification depends on", "Was it entered quickly? Was it entered slowly? — because speed of entry affects classification"]}'::jsonb, '{"answer": 1, "explain": "First check the type (wrong type = erroneous); if it is the right type, check where it sits relative to the range (typical = normal, at the edge = boundary, outside = invalid)."}'::jsonb),
('computer-science:2-3-2-testing:tips:47089799', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'tips', 'mcq', 1, '{"readingTitle": "explain — Syntax vs logic: how each is actually found", "reading": "<p>Questions often ask you to explain the difference between a syntax and a logic error, INCLUDING how each is found — both halves are needed for full marks.</p>\n<ul>\n<li><strong>Syntax error:</strong> breaks the rules of the language, so the program can''t be translated or run. Found <strong>automatically</strong> — the translator reports an error message.</li>\n<li><strong>Logic error:</strong> the program runs fine, but gives the wrong result. Found by <strong>testing</strong> — running the program and comparing its actual output with the expected output.</li>\n</ul>\n<p>Memory hook: the translator catches broken <em>rules</em>; only testing catches broken <em>reasoning</em>.</p>", "question": "A student says ''a syntax error is worse than a logic error because it''s harder to find''. Is this correct?", "options": ["Yes, since logic errors are always spotted instantly by the translator without any testing being needed at all", "No — it is the opposite: syntax errors are caught automatically by the translator, while logic errors need testing to find", "Yes, since a syntax error can genuinely only ever be found by comparing actual and expected output during real testing", "No, because it is sometimes claimed that neither type of error can actually ever be found before a program has been fully released"]}'::jsonb, '{"answer": 1, "explain": "Syntax errors are usually easier to find (the translator reports them automatically). Logic errors are harder — they need testing, since the translator can''t detect them."}'::jsonb),
('computer-science:2-3-2-testing:tips:0f1c1716', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'tips', 'mcq', 1, '{"readingTitle": "tip — Writing a strong test plan", "reading": "<p>\"Create a test plan for...\" questions are marked on covering the input properly, not just picking any four numbers. Structure your answer as a table with: <strong>test data</strong>, <strong>type of test data</strong>, and <strong>expected result</strong>.</p>\n<ul>\n<li>Include <strong>one value of each type</strong> — normal, boundary, invalid and erroneous — so every part of the accepted-input rule is actually tested.</li>\n<li>For each row, state the expected result as simply <strong>accepted</strong> or <strong>rejected</strong> (unless the question asks for a specific calculated output).</li>\n</ul>\n<p><strong>Example</strong> (whole number 1–20): 12 → normal → accepted; 20 → boundary → accepted; 21 → invalid → rejected; \"twelve\" → erroneous → rejected.</p>", "question": "A ''create a test plan'' question is marked mainly on what?", "options": ["Choosing exactly four random numbers, since the specific values chosen never actually seem to matter", "Covering all four types of test data with a suitable value and a correct expected result for each", "Writing out the longest possible list of numbers, since more test data always seems to mean more marks", "Only ever including normal data, since boundary, invalid and erroneous data are treated as optional extras"]}'::jsonb, '{"answer": 1, "explain": "Marks come from covering normal, boundary, invalid and erroneous data with a suitable value and a correctly stated expected result (accepted/rejected) for each."}'::jsonb),
('computer-science:2-3-2-testing:fib:cda1096f', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'fib', 'fib', 1, '{"question": "_____ testing checks modules or parts of a program repeatedly, as it is developed.", "blankOptions": {"B1": ["logic", "iterative", "boundary", "erroneous"]}}'::jsonb, '{"blanks": {"B1": "iterative"}}'::jsonb),
