('computer-science:2-3-2-testing:match:229a2d26', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Testing”?", "options": ["Finding and fixing an error once testing has located it", "Using test results to correct problems in a program, then re-testing", "Typical, valid data that the program should accept and process correctly", "Checking that a program works correctly and meets its requirements, and finding any errors before release"]}'::jsonb, '{"answer": 3, "explain": "“Testing” means: Checking that a program works correctly and meets its requirements, and finding any errors before release"}'::jsonb),
('computer-science:2-3-2-testing:match:29c1ed2d', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Debugging”?", "options": ["Data of the correct type, but outside the accepted range, which should be rejected", "Finding and fixing an error once testing has located it", "An error that lets the program run, but produces the wrong result", "Data of the wrong type entirely, which should be rejected"]}'::jsonb, '{"answer": 1, "explain": "“Debugging” means: Finding and fixing an error once testing has located it"}'::jsonb),
('computer-science:2-3-2-testing:match:0765ddf8', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Iterative testing”?", "options": ["Testing modules or parts of a program repeatedly as it is developed and refined", "Testing the complete, finished program against its original requirements", "A table recording the test data, its type, and the expected and actual results", "Data of the correct type, but outside the accepted range, which should be rejected"]}'::jsonb, '{"answer": 0, "explain": "“Iterative testing” means: Testing modules or parts of a program repeatedly as it is developed and refined"}'::jsonb),
('computer-science:2-3-2-testing:match:ad303b84', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Final (terminal) testing”?", "options": ["An error that lets the program run, but produces the wrong result", "An error that breaks the rules of the programming language, so the program cannot be translated or run", "Data of the wrong type entirely, which should be rejected", "Testing the complete, finished program against its original requirements"]}'::jsonb, '{"answer": 3, "explain": "“Final (terminal) testing” means: Testing the complete, finished program against its original requirements"}'::jsonb),
('computer-science:2-3-2-testing:match:e140c34e', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Syntax error”?", "options": ["An error that breaks the rules of the programming language, so the program cannot be translated or run", "Data of the wrong type entirely, which should be rejected", "Data of the correct type, but outside the accepted range, which should be rejected", "An error that lets the program run, but produces the wrong result"]}'::jsonb, '{"answer": 0, "explain": "“Syntax error” means: An error that breaks the rules of the programming language, so the program cannot be translated or run"}'::jsonb),
('computer-science:2-3-2-testing:match:2f11084a', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Logic error”?", "options": ["Data of the wrong type entirely, which should be rejected", "Data right at the edge of what the program accepts — the minimum or maximum valid value", "Data of the correct type, but outside the accepted range, which should be rejected", "An error that lets the program run, but produces the wrong result"]}'::jsonb, '{"answer": 3, "explain": "“Logic error” means: An error that lets the program run, but produces the wrong result"}'::jsonb),
('computer-science:2-3-2-testing:match:ca9ab07a', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Normal test data”?", "options": ["Data of the correct type, but outside the accepted range, which should be rejected", "Typical, valid data that the program should accept and process correctly", "Testing modules or parts of a program repeatedly as it is developed and refined", "Finding and fixing an error once testing has located it"]}'::jsonb, '{"answer": 1, "explain": "“Normal test data” means: Typical, valid data that the program should accept and process correctly"}'::jsonb),
('computer-science:2-3-2-testing:match:f2a17527', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Boundary (extreme) test data”?", "options": ["An error that breaks the rules of the programming language, so the program cannot be translated or run", "Using test results to correct problems in a program, then re-testing", "Data right at the edge of what the program accepts — the minimum or maximum valid value", "Data of the wrong type entirely, which should be rejected"]}'::jsonb, '{"answer": 2, "explain": "“Boundary (extreme) test data” means: Data right at the edge of what the program accepts — the minimum or maximum valid value"}'::jsonb),
('computer-science:2-3-2-testing:match:8a213bb4', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Invalid test data”?", "options": ["Testing the complete, finished program against its original requirements", "Data of the correct type, but outside the accepted range, which should be rejected", "Finding and fixing an error once testing has located it", "Using test results to correct problems in a program, then re-testing"]}'::jsonb, '{"answer": 1, "explain": "“Invalid test data” means: Data of the correct type, but outside the accepted range, which should be rejected"}'::jsonb),
('computer-science:2-3-2-testing:match:940a741b', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Erroneous test data”?", "options": ["Testing modules or parts of a program repeatedly as it is developed and refined", "Data of the wrong type entirely, which should be rejected", "Data right at the edge of what the program accepts — the minimum or maximum valid value", "Data of the correct type, but outside the accepted range, which should be rejected"]}'::jsonb, '{"answer": 1, "explain": "“Erroneous test data” means: Data of the wrong type entirely, which should be rejected"}'::jsonb),
('computer-science:2-3-2-testing:match:723e83d4', 'computer-science', 'computer-science:2-3-2-testing', '2.3.2 Testing', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Test plan”?", "options": ["An error that lets the program run, but produces the wrong result", "Data right at the edge of what the program accepts — the minimum or maximum valid value", "A table recording the test data, its type, and the expected and actual results", "An error that breaks the rules of the programming language, so the program cannot be translated or run"]}'::jsonb, '{"answer": 2, "explain": "“Test plan” means: A table recording the test data, its type, and the expected and actual results"}'::jsonb),
