('computer-science:2-4-1-boolean-logic:match:a7c8688f', 'computer-science', 'computer-science:2-4-1-boolean-logic', '2.4.1 Boolean Logic', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “OR gate”?", "options": ["A table of every input combination and its output", "Has one input and outputs the opposite value", "Show which gate is worked out first", "Outputs 1 when at least one input is 1"]}'::jsonb, '{"answer": 3, "explain": "“OR gate” means: Outputs 1 when at least one input is 1"}'::jsonb)
